// src/components/LiveMap.jsx
import React from 'react';

export default function LiveMap({ complaints = [], singlePin, singleCoords, height = '100%', onPinClick }) {
  // Base boundary anchors mapping precisely around the coordinates vector matrix of Nagpur Station
  const baseLat = 21.1522;
  const baseLng = 79.0882;

  return (
    <div style={{ height, width: '100%', background: '#1A2634', borderRadius: 12, border: '1px solid #34495E', position: 'relative', overflow: 'hidden', boxShadow: 'inset 0 0 20px rgba(0,0,0,0.5)' }}>
      
      {/* 🗺️ REALISTIC GOOGLE SATELLITE / RADAR BACKGROUND MAP INTERFACE */}
      <img 
        src="https://maps.app.goo.gl/CEU6Y61dq6TE9Qb57" 
        alt="Nagpur Station Structural Track Matrix" 
        style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', objectFit: 'cover', opacity: 0.25, pointerEvents: 'none' }} 
      />

      {/* Background Structural Matrix Grid Design Overlays */}
      <div style={{ position: 'absolute', inset: 0, opacity: 0.15, background: 'linear-gradient(#00d2ff 1px, transparent 1px), linear-gradient(90deg, #00d2ff 1px, transparent 1px)', backgroundSize: '30px 30px' }} />
      
      <div style={{ position: 'absolute', top: 10, left: 10, background: 'rgba(10,22,40,0.9)', color: '#00d2ff', padding: '5px 10px', borderRadius: 6, fontSize: 10, fontFamily: 'monospace', fontWeight: 'bold', zIndex: 10, border: '1px solid #00d2ff', boxShadow: '0 0 10px rgba(0,210,255,0.3)' }}>
        🛰️ GOOGLE RADAR LIVE STREAM: NAGPUR STATION GRID
      </div>

      <div style={{ width: '100%', height: '100%', position: 'relative' }}>
        {singlePin && singleCoords ? (
          // Cleaner targeted radar locking
          <div style={{ position: 'absolute', left: '50%', top: '50%', transform: 'translate(-50%, -50%)', textAlign: 'center', zIndex: 5 }}>
            <div style={{ fontSize: 32, animation: 'bounce 1s infinite alternate', filter: 'drop-shadow(0 2px 5px rgba(0,0,0,0.5))' }}>📍</div>
            <div style={{ background: '#FF1744', color: '#fff', fontSize: 9, padding: '3px 6px', borderRadius: 4, whiteSpace: 'nowrap', fontWeight: 700, boxShadow: '0 2px 8px rgba(255,23,68,0.5)' }}>LIVE TARGET TRACK</div>
          </div>
        ) : (
          // General scatter mapping of incoming alerts across platforms
          complaints.map((c, idx) => {
            // Delta computation scaling logic coordinates positions inside tracking window interface
            const latDelta = (c.lat - baseLat) * 10000; 
            const lngDelta = (c.lng - baseLng) * 10000;

            // Mathematical positioning tweaks to ensure pins align seamlessly inside viewport box
            const leftPct = 50 + (lngDelta * 3.2);
            const topPct = 50 - (latDelta * 3.2);

            return (
              <div 
                key={c.id || idx} 
                onClick={() => onPinClick && onPinClick(c)}
                style={{ 
                  position: 'absolute', 
                  left: `${Math.max(10, Math.min(leftPct, 90))}%`, 
                  top: `${Math.max(10, Math.min(topPct, 90))}%`, 
                  transform: 'translate(-50%, -50%)', 
                  cursor: 'pointer',
                  zIndex: 5,
                  transition: 'all 0.2s ease'
                }} 
                title={`${c.area} - ${c.gtype}`}
              >
                {/* Visual Pulse Wave Radar Ripple effect around live markers */}
                <div style={{ position: 'absolute', width: 24, height: 24, background: c.status === 'NEW' ? 'rgba(255,23,68,0.2)' : 'rgba(0,230,118,0.2)', borderRadius: '50%', transform: 'translate(-2px, -2px)', animation: 'ping 1.5s cubic-bezier(0, 0, 0.2, 1) infinite' }} />
                
                <div style={{ fontSize: 22, filter: 'drop-shadow(0 2px 4px rgba(0,0,0,0.4))' }}></div>
                <div style={{ 
                  width: 8, 
                  height: 8, 
                  background: c.status === 'NEW' ? '#FF1744' : c.status === 'IN_PROGRESS' ? '#AA00FF' : '#00E676', 
                  borderRadius: '50%', 
                  border: '1.5px solid #fff', 
                  margin: '-2px auto 0 auto',
                  boxShadow: '0 1px 3px rgba(0,0,0,0.5)'
                }} />
              </div>
            );
          })
        )}
      </div>

      {/* Embedded CSS Classes for seamless keyframe pulse and bounce matrix animations */}
      <style>{`
        @keyframes ping {
          0% { transform: scale(0.8); opacity: 1; }
          100% { transform: scale(2.2); opacity: 0; }
        }
        @keyframes bounce {
          from { transform: translate(-50%, -45%); }
          to { transform: translate(-50%, -60%); }
        }
      `}</style>
    </div>
  );
}
